      faq: [
        { question: 'Hvilke mattebegreper dekker barnehage-lekearbeidsark?', answer: 'De adresserer telling til tjue, addisjon og subtraksjon innenfor ti med lekesamlinger, størrelsessammenligning og seriasjon med tre eller flere gjenstander, fleregenskapssortering og grunnleggende datainnsamling om lekepreferanser. Disse aktivitetene samsvarer med Kunnskapsløftets mål for telling, operasjoner, måling og data i barnehagen.' },
        { question: 'Hvordan bygger lekearbeidsark ordforråd hos barnehagebarn?', answer: 'De introduserer beskrivende adjektiver som myk, hard, rund, firkantet, størst og minst sammen med lekenavn og handlingsord som dele, bygge, rulle og stable. Dette rike beskrivende ordforrådet støtter både faglig skriving og muntlig kommunikasjon, og gir barn presist språk for å beskrive gjenstander og lekeopplevelser.' },
        { question: 'Kan lekearbeidsark adressere sosiale ferdigheter i barnehagen?', answer: 'Ja. Aktiviteter med delingsscenarier, turventingsillustrasjoner og samarbeidslek-situasjoner bygger det sosiale ordforrådet og begrepene barnehagebarn trenger for vellykket samhandling med jevnaldrende. Å diskutere disse scenariene på papir, i en rolig analytisk kontekst, forbereder barn på å anvende de samme ferdighetene under emosjonelt ladede virkelige lekeøyeblikk.' },
      ],

      snippetAnswer: 'Leke-oppgaver for barnehageklassen (5–6 år) bruker dukker, biler, klosser og brettspill til å trene telling, sortering etter flere egenskaper og begynnende skriving av lekenavn. Kjente leker gjør abstrakt læring konkret. Gratis utskrivbare PDF-oppgaver på LessonCraftStudio.',
      uniqueGradeAngle: 'Leketemaet får en ny dimensjon i barnehageklassen fordi fem- og seksåringer går fra parallell lek til samarbeidende regelbasert lek — de forhandler om regler, fordeler leker rettferdig og organiserer lekesamlinger. Mens førskolebarn lekte fritt, kan barn i barnehageklassen telle og sortere leker etter type, materiale og størrelse samtidig, løse fordelingsoppgaver (12 klosser delt på 3 barn), og skrive lister over yndlingsleker. Addisjon og subtraksjon knyttes til hverdagsscenarier: du har åtte biler og gir bort tre, hvor mange har du igjen? Skriving av lekenavn trener begynnende staveferdigheter med ord barnet kjenner intimt. Rammeplanens mål for lek, læring og danning støttes når barn kobler sine egne leker med strukturert læring.',
      developmentalMilestones: [
        { milestone: 'Klassifisering etter flere egenskaper (5–6-åringer kan sortere etter to kriterier samtidig)', howWeAddress: 'Lekesorteringsark der barn plasserer leker i kategorier etter både type og materiale bygger logisk flerdimensjonal tenkning' },
        { milestone: 'Rettferdig fordeling (tidlig divisjonsforståelse)', howWeAddress: 'Fordelingsoppgaver der leker deles likt mellom barn gir praktisk introduksjon til rettferdig deling' },
        { milestone: 'Skriving av hverdagsord (lekenavn)', howWeAddress: 'Ordsporing og skriving av kjente lekenavn (ball, bil, dukke) gir motiverende skrivetrening i personlig kontekst' },
      ],
      differentiationNotes: 'For barn som trenger støtte, begrens til barnets egne favorittleker, hold sorteringen til én egenskap og tellingen innenfor 10. For avanserte barn i barnehageklassen, introduser flerdimensjonal sortering (type pluss farge pluss størrelse), fordelingsoppgaver med rest, og selvstendig skriving av lekebeskrivelser og ønskelister.',
      parentTakeaway: 'Barnets egen lekekasse er et gratis matematikkverksted. Tell leker sammen, sorter etter type (biler, dukker, klosser), og øv fordeling: «hvordan deler vi 10 klosser likt mellom deg og søsteren din?» La barnet skrive en ønskeliste med lekenavn. Opprydding er telling: «hvor mange biler la du tilbake i kassen?» Oppgavearkene formaliserer det barnet allerede gjør daglig med leker.',
      classroomIntegration: 'Leketemaet integreres i barnehageklassens hverdag: i samlingen diskuteres favorittleker og regler for å dele, ved læringsstasjoner arbeides det med sorterings- og fordelingsark, i lekekroken organiseres leker etter kategorier, og i matematikkstunden brukes konkrete leker som tellemateriale. Rammeplanens mål for lek, danning og sosiale ferdigheter integreres i stasjonsarbeidet.',
      assessmentRubric: [
        { skill: 'Lekesortering etter flere egenskaper', emerging: 'sorterer leker i 2 grupper etter én egenskap med støtte', proficient: 'sorterer selvstendig etter to egenskaper (type og materiale) i 4+ grupper', advanced: 'oppretter egne sorteringskriterier og forklarer dem til andre' },
        { skill: 'Rettferdig fordeling av leker', emerging: 'fordeler leker med én-til-én-korrespondanse med støtte', proficient: 'fordeler selvstendig leker likt mellom 2–3 barn og bekrefter med telling', advanced: 'løser fordelingsoppgaver med rest og forklarer hva som skjer med det som er til overs' },
        { skill: 'Skriving av lekenavn', emerging: 'sporer 2–3 lekenavn på prikkede linjer', proficient: 'skriver selvstendig 5–6 vanlige lekenavn leselig', advanced: 'skriver lekenavn i korte setninger og lager egne ønskelister' },
      ],
